          outputVoltages: outs.map(o => o.voltage),
          outputCurrents: outs.map(o => (o.voltage > 0 ? o.power / o.voltage : 0)),
          switchingFrequency: opFreq,
          ambientTemperature: this.localData.ambientTemperature,
