        formatSi(value, unit, decimals = 3) {
            if (value == null || !isFinite(value)) return '—';
            const abs = Math.abs(value);
            const steps = [
                { t: 1e9,  s: 'G' }, { t: 1e6,  s: 'M' }, { t: 1e3,  s: 'k' },
                { t: 1,    s: ''  },
                { t: 1e-3, s: 'm' }, { t: 1e-6, s: 'µ' }, { t: 1e-9, s: 'n' }, { t: 1e-12, s: 'p' },
